export function _inferBranch(obj: Record<string, unknown>, candidates: string[]): string | null {
  const keys = Object.keys(obj).filter(k => k !== 'children');
  let best: string | null = null;
  let bestScore = 0;
  let bestMatches = 0;
  for (const c of candidates) {
    const fields = _BRANCH_FIELDS[c];
    if (!fields) continue;
    const fieldSet = new Set(fields);
    let matches = 0, misses = 0;
    for (const k of keys) { if (fieldSet.has(k)) matches++; else misses++; }
    if (matches === 0) continue;
    const score = matches * 2 - misses;
    if (score > bestScore || (score === bestScore && matches > bestMatches)) { bestScore = score; bestMatches = matches; best = c; }
  }
  return best;
}
